//-----------------------------------------------------------Magnemite---------------------------------------------------
void computeSurfaceNormal(GLfloat vertex1[],
                          GLfloat vertex2[],
                          GLfloat vertex3[],
                          GLfloat normal[])
{
    GLfloat v1[3], v2[3];
    v1[0] = vertex3[0] - vertex2[0];
    v1[1] = vertex3[1] - vertex2[1];
    v1[2] = vertex3[2] - vertex2[2];
    v2[0] = vertex1[0] - vertex2[0];
    v2[1] = vertex1[1] - vertex2[1];
    v2[2] = vertex1[2] - vertex2[2];
    normal[0] = v1[1] * v2[2] - v1[2] * v2[1];
    normal[1] = v1[2] * v2[0] - v1[0] * v2[2];
    normal[2] = v1[0] * v2[1] - v1[1] * v2[0];
    GLfloat magnitude = sqrt(normal[0] * normal[0] + normal[1] * normal[1] + normal[2] * normal[2]);
    normal[0] /= magnitude;
    normal[1] /= magnitude;
    normal[2] /= magnitude;
}

void Body::draw()
{
    // Draw grey body
    glColor3f(0.55f, 0.79f, 0.80f);
    glutSolidSphere(2.0, 30, 30);

    // Draw white eyeball as a small sphere
    glPushMatrix();
    glTranslatef(0.0f, 0.0f, 0.7f); // Stick it slightly out from body (2.0 is body radius)
    glColor3f(1.0f, 1.0f, 1.0f);
    glutSolidSphere(1.4f, 60, 60); // Small white sphere as eyeball
    glPopMatrix();

    // Pupil
    glPushMatrix();
    glTranslatef(0.0f, 0.0f, 1.9f); // Slightly in front of white sphere
    glColor3f(0.0f, 0.0f, 0.0f);
    glutSolidSphere(0.3f, 20, 20); // Smaller sphere for pupil
    glPopMatrix();
}

void drawBentCylinder::drawCube(float size, float r, float g, float b) const
{
    float half = size / 2.0f;

    glColor3f(r, g, b);

    glBegin(GL_QUADS);
    // Front face
    glNormal3f(0, 0, 1);
    glVertex3f(-half, -half, half);
    glVertex3f(half, -half, half);
    glVertex3f(half, half, half);
    glVertex3f(-half, half, half);

    // Back face
    glNormal3f(0, 0, -1);
    glVertex3f(-half, -half, -half);
    glVertex3f(half, -half, -half);
    glVertex3f(half, half, -half);
    glVertex3f(-half, half, -half);

    // Left face
    glNormal3f(-1, 0, 0);
    glVertex3f(-half, -half, -half);
    glVertex3f(-half, -half, half);
    glVertex3f(-half, half, half);
    glVertex3f(-half, half, -half);

    // Right face
    glNormal3f(1, 0, 0);
    glVertex3f(half, -half, -half);
    glVertex3f(half, -half, half);
    glVertex3f(half, half, half);
    glVertex3f(half, half, -half);

    // Bottom face
    glNormal3f(0, -1, 0);
    glVertex3f(-half, -half, -half);
    glVertex3f(half, -half, -half);
    glVertex3f(half, -half, half);
    glVertex3f(-half, -half, half);

    // Top face
    glNormal3f(0, 1, 0);
    glVertex3f(-half, half, -half);
    glVertex3f(half, half, -half);
    glVertex3f(half, half, half);
    glVertex3f(-half, half, half);
    glEnd();
}

void drawBentCylinder::drawCylinderSegment(GLUquadric *quad, float radius, float height) const
{
    gluCylinder(quad, radius, radius, height, 20, 1);
    gluDisk(quad, 0.0f, radius, 20, 1);
    glTranslatef(0.0f, 0.0f, height);
    gluDisk(quad, 0.0f, radius, 20, 1);
    glTranslatef(0.0f, 0.0f, -height);
}

void drawBentCylinder::draw() const
{

    GLUquadric *quad = gluNewQuadric();
    gluQuadricNormals(quad, GLU_SMOOTH);

    glColor3f(0.913f, 0.921f, 0.925f); // Grey bent cylinder
    glDisable(GL_CULL_FACE);

    float totalAngle = endAngle - startAngle;
    float angleStep = totalAngle / segments;

    // Draw bent cylinder segments
    for (int i = 0; i < segments; ++i)
    {
        float angle = startAngle + i * angleStep;
        float nextAngle = angle + angleStep;
        float midAngle = (angle + nextAngle) / 2.0f;

        float x = bendRadius * cos(midAngle);
        float y = bendRadius * sin(midAngle);

        glPushMatrix();
        glTranslatef(x, y, 0.0f);
        glRotatef((midAngle * 180.0f / M_PI) + 90.0f, 0.0f, 0.0f, 1.0f);

        // Center the segment
        glTranslatef(0.0f, 0.0f, -segmentHeight / 2.0f);

        drawCylinderSegment(quad, cylRadius, segmentHeight);

        glPopMatrix();
    }

    // Variables for cube drawing
    float spacing = cylRadius * 2.0f;
    float shiftAmount = cylRadius - segmentHeight / 2.0f;
    float cubeSize = cylRadius * 2.0f;

    // Draw cubes at end of bent cylinder
    float endX = bendRadius * cos(endAngle);
    float endY = bendRadius * sin(endAngle);
    float endTangentAngleDeg = (endAngle + M_PI / 2.0f) * 180.0f / M_PI;

    for (int i = 0; i < 3; ++i)
    {
        glPushMatrix();
        glTranslatef(endX, endY - cylRadius, 0.0f);
        glRotatef(endTangentAngleDeg, 0.0f, 0.0f, 1.0f);

        float offsetX = shiftAmount + i * spacing;
        glTranslatef(offsetX, 0.0f, 0.0f);

        if (i == 2)
            drawCube(cubeSize, 1.0f, 0.0f, 0.0f); // Red final cube
        else
            drawCube(cubeSize, 0.913f, 0.921f, 0.925f); // Grey cubes

        glPopMatrix();
    }

    // Draw mirrored cubes at start of bent cylinder
    float startX = bendRadius * cos(startAngle);
    float startY = bendRadius * sin(startAngle);
    float startTangentAngleDeg = (startAngle + M_PI / 2.0f) * 180.0f / M_PI;

    for (int i = 0; i < 3; ++i)
    {
        glPushMatrix();
        glTranslatef(startX, startY - cylRadius, 0.0f);
        glRotatef(startTangentAngleDeg, 0.0f, 0.0f, 1.0f);

        float offsetX = shiftAmount + i * spacing;
        glTranslatef(-offsetX, 0.0f, 0.0f); // mirror by negating offset

        if (i == 2)
            drawCube(cubeSize, 0.196f, 0.564f, 0.984f); // Blue final cube
        else
            drawCube(cubeSize, 0.913f, 0.921f, 0.925f); // Grey cubes

        glPopMatrix();
    }

    gluDeleteQuadric(quad);
    glEnable(GL_CULL_FACE);
}

void Screws::draw() const
{
    // Draw torus
    glPushMatrix();
    glTranslatef(0.0f, 0.0f, 0.0f);  // Move to origin
    glRotatef(90, 1.0f, 0.0f, 0.0f); // Rotate if needed
    glColor3f(0.97f, 0.96f, 0.92f);
    glutSolidTorus(0.1f, 0.8f, 30, 50); // A donut!

    // Create quadric once for cylinder and disks
    GLUquadric *quad = gluNewQuadric();

    // Draw cylinder through center
    glPushMatrix();
    glColor3f(0.97f, 0.96f, 0.92f);          // Metallic color cylinder
    glRotatef(0, 1, 0, 0);                   // Align along Z axis (OpenGL's cylinder is along Y)
    glTranslatef(0.0f, 0.0f, -0.1f);         // Move it down so it centers at origin
    gluCylinder(quad, 0.3, 0.3, 1.0, 30, 1); // (quad, base, top, height, slices, stacks)
    glPopMatrix();

    // Draw back disk (facing -Y)
    glPushMatrix();
    glColor3f(0.97f, 0.96f, 0.92f);
    glTranslatef(0.0f, 0.0f, 0.1f); // Centered at origin
    gluDisk(quad, 0.0, 0.8, 50, 1); // inner radius = 0.0, outer = inner radius of torus
    glPopMatrix();

    // Delete quadric after disks and cylinder are done
    gluDeleteQuadric(quad);

    // Draw the threads
    glDisable(GL_CULL_FACE);

    for (int i = 0; i < 3; ++i)
    {
        float z = 0.2f + i * 0.2f;

        glPushMatrix();
        glColor3f(0.3f, 0.3f, 0.3f);
        glTranslatef(0.0f, 0.0f, z);

        GLUquadric *quad = gluNewQuadric();

        // Bottom cap
        gluDisk(quad, 0.0, 0.4, 50, 1);

        // Cylinder body
        gluCylinder(quad, 0.4, 0.4, 0.1, 30, 1);

        // Top cap
        glPushMatrix();
        glTranslatef(0.0f, 0.0f, 0.1f);
        gluDisk(quad, 0.0, 0.4, 50, 1);
        glPopMatrix();

        gluDeleteQuadric(quad);
        glPopMatrix();
    }

    glEnable(GL_CULL_FACE);

    // Draw dome
    glDisable(GL_CULL_FACE);
    glTranslatef(0.0f, 0.0f, 0.05f);
    glColor3f(0.97f, 0.96f, 0.92f);

    int slices = 50, stacks = 25;
    float radius = 0.9f;

    for (int i = 0; i <= stacks; ++i)
    {
        float lat0 = M_PI * (-0.5 + (float)(i) / stacks);
        float lat1 = M_PI * (-0.5 + (float)(i + 1) / stacks);

        if (lat1 > 0)
            break; // Only draw up to equator

        float z0 = radius * sin(lat0);
        float zr0 = radius * cos(lat0);
        float z1 = radius * sin(lat1);
        float zr1 = radius * cos(lat1);

        glBegin(GL_QUAD_STRIP);
        for (int j = 0; j <= slices; ++j)
        {
            float lng = 2 * M_PI * (float)(j) / slices;
            float x = cos(lng);
            float y = sin(lng);

            glNormal3f(x * zr0, y * zr0, z0);
            glVertex3f(x * zr0, y * zr0, z0);
            glNormal3f(x * zr1, y * zr1, z1);
            glVertex3f(x * zr1, y * zr1, z1);
        }
        glEnd();
    }

    glPopMatrix();
}

void MyPoints::draw()
{
    glPointSize(1.0);
    srand(1); // Fixed random seed for reproducibility; remove for random behavior on each run

    glColor3f(1.0f, 1.0f, 0.0f); // Set point color to yellow
    GLfloat x, y, z;
    GLfloat radius, theta, phi;

    glBegin(GL_POINTS);

    for (int i = 0; i < 1000; ++i)
    {
        // Generate a random radius uniformly distributed within the sphere
        radius = ((rand() % 10000) / 10000.0) * 20.0; // Radius in the range [0, 20]

        // Random azimuthal angle (theta) in the range [0, 2π]
        theta = ((rand() % 10000) / 10000.0) * 2.0 * M_PI; // Azimuthal angle

        // Random polar angle (phi) in the range [0, π]
        phi = acos(1.0 - 2.0 * (rand() % 10000) / 10000.0); // Polar angle (from 0 to π)

        // Convert spherical coordinates to Cartesian coordinates
        x = radius * sin(phi) * cos(theta);
        y = radius * sin(phi) * sin(theta);
        z = radius * cos(phi);

        glVertex3f(x, y, z); // Draw the point at (x, y, z)
    }

    glEnd();
}

// Rename this function from draw() to drawMagnemiteDetailed()
void Magnemite::drawMagnemiteDetailed()
{
    // Draw body
    body.draw();

    // Create the screws
    glPushMatrix();
    glTranslatef(0.0f, 2.5f, 0.0f);
    glScalef(0.7f, 0.7f, 0.7f);
    screws.draw();
    glPopMatrix();

    glPushMatrix();
    glRotatef(135, 1.0f, 0.0f, 0.0f);
    glRotatef(45, 0.0f, 0.0f, 1.0f);
    glTranslatef(0.0f, 2.5f, 0.0f);
    glScalef(0.7f, 0.7f, 0.7f);
    screws.draw();
    glPopMatrix();

    glPushMatrix();
    glRotatef(135, 1.0f, 0.0f, 0.0f);
    glRotatef(-45, 0.0f, 0.0f, 1.0f);
    glTranslatef(0.0f, 2.5f, 0.0f);
    glScalef(0.7f, 0.7f, 0.7f);
    screws.draw();
    glPopMatrix();

    // Create hands
    float t = glutGet(GLUT_ELAPSED_TIME) / 1000.0f;
    // Stop motion if fainted
    if (isFainted)
    {
        t = 0.0f; // Freeze time to stop motion
    }
    float degrees_per_second = 60.0f;
    float angle = t * degrees_per_second;

    glPushMatrix();
    glRotated(-30.0, 0.0f, 0.0f, 1.0f);
    glTranslatef(-3.5f, 0.0f, 0.0f);
    glRotated(-90.0, 0.0f, 0.0f, 1.0f);
    glRotatef(angle, 0.0f, 1.0f, 0.0f);
    float scaleFactor = 5.0f;
    glScalef(scaleFactor, scaleFactor, scaleFactor);
    drawbentcylinder.draw();
    glPopMatrix();

    glPushMatrix();
    glRotated(30.0, 0.0f, 0.0f, 1.0f);
    glTranslatef(3.5f, 0.0f, 0.0f);
    glRotated(90.0, 0.0f, 0.0f, 1.0f);
    glRotatef(angle, 0.0f, 1.0f, 0.0f);
    glScalef(scaleFactor, scaleFactor, scaleFactor);
    drawbentcylinder.draw();
    glPopMatrix();

    // Create electric field
    if (isFainted)
    {
        return;
    }
    else
    {
        mypoints.draw();
    }
}

// Update drawMagnemite() to call the renamed function
void Magnemite::drawMagnemite()
{
    float t = glutGet(GLUT_ELAPSED_TIME) / 1000.0f;

    // Stop motion if fainted
    if (isFainted)
    {
        t = 0.0f; // Freeze time to stop motion
    }

    // First Magnemite (Infinity path)
    float t1 = t;
    float motionX1 = 10.0f * sin(t1);
    float motionY1 = 5.0f * sin(t1) * cos(t1);

    // Second Magnemite (Circle path)
    float t2 = t + 2.0f;
    float motionX2 = 8.0f * cos(t2);
    float motionY2 = 8.0f * sin(t2);

    // Third Magnemite (Reverse circle path)
    float t3 = t + 12.0f;
    float motionX3 = 8.0f * cos(t3);
    float motionY3 = 8.0f * sin(t3);

    // First Magnemite
    glPushMatrix();
    glTranslatef(motionX1, motionY1, 0.0f);
    // Apply faint rotation if fainted
    if (isFainted)
    {
        glRotatef(faintRotation, 1.0f, 0.0f, 0.0f); // Rotate around Z-axis to lay down
    }
    drawMagnemiteDetailed();
    glPopMatrix();

    // Second Magnemite
    glPushMatrix();
    glTranslatef(5.0f + motionX2, 3.0f + motionY2, 6.0f);
    if (isFainted)
    {
        glRotatef(faintRotation, 1.0f, 0.0f, 0.0f); // Rotate around Z-axis to lay down
    }
    drawMagnemiteDetailed();
    glPopMatrix();

    // Third Magnemite
    glPushMatrix();
    glTranslatef(-5.0f + motionX3, 1.5f + motionY3, -6.0f);
    if (isFainted)
    {
        glRotatef(faintRotation, 1.0f, 0.0f, 0.0f); // Rotate around Z-axis to lay down
    }
    drawMagnemiteDetailed();
    glPopMatrix();
}

void Magnemite::drawMagneton()
{
    float t = glutGet(GLUT_ELAPSED_TIME) / 1000.0f;

    // Stop motion if fainted
    if (isFainted)
    {
        t = 0.0f; // Freeze time to stop motion
    }
    float t4 = t;
    float motionX4 = 10.0f * sin(t4);
    float motionY4 = 0.8f * sin(t4) * cos(t4);

    glPushMatrix();
    glTranslatef(motionX4, motionY4, 0.0f);

    // Apply faint rotation to entire Magneton group
    if (isFainted)
    {
        glRotatef(faintRotation, 1.0f, 0.0f, 0.0f); // Rotate around Z-axis to lay down
    }

    // Center Magnemite
    glPushMatrix();
    glTranslatef(0.0f, 0.0f, 0.0f);
    drawMagnemiteDetailed(); // Use the detailed function here too
    glPopMatrix();

    // Left Magnemite
    glPushMatrix();
    glRotatef(-15, 0.0f, 1.0f, 0.0f);
    glTranslatef(-2.5f, -3.0f, 0.0f);
    glRotatef(100, 0.0f, 0.0f, 1.0f);
    drawMagnemiteDetailed();
    glPopMatrix();

    // Right Magnemite
    glPushMatrix();
    glRotatef(15, 0.0f, 1.0f, 0.0f);
    glTranslatef(2.5f, -3.0f, 0.0f);
    glRotatef(-100, 0.0f, 0.0f, 1.0f);
    drawMagnemiteDetailed();
    glPopMatrix();

    glPopMatrix();
}

// Keep your switching function as is
void Magnemite::draw()
{
    if (isMagneton)
    {
        drawMagneton(); // Draw Magneton model
    }
    else
    {
        drawMagnemite(); // Draw Magnemite model
    }
}

void Magnemite::evolveToMagneton()
{
    if (!isMagneton)
    {

        isMagneton = true;
    }
}

void Magnemite::devolveToMagnemite()
{
    if (isMagneton)
    {

        isMagneton = false;
    }
}

void Magnemite::updateFaintAnimation()
{
    if (!isFainted || faintAnimationComplete)
        return;

    faintAnimationTimer += 1.0f;      // Increment timer
    float animationDuration = 120.0f; // 2 seconds at 60fps

    if (faintAnimationTimer < animationDuration)
    {
        // Rotate from 0 to 90 degrees (laying down)
        float progress = faintAnimationTimer / animationDuration;
        faintRotation = progress * -90.0f;
    }
    else
    {
        faintRotation = -90.0f;
        faintAnimationComplete = true;
    }
}

