//--------------------------------------------------------Battle Platform--------------------------------------------------------//

void Battle_Platform::drawPlat()
{
    glDisable(GL_CULL_FACE);               // Disable back-face culling to render all faces
    GLUquadricObj *pObj = gluNewQuadric(); // Create a new quadric object for curved shapes

    // Draw the bottom rectangular base
    glPushMatrix();
    glColor3f(0.8f, 0.8f, 0.8f);     // Light gray color
    glTranslatef(0.0f, -2.0f, 0.0f); // Lower the base vertically
    glScalef(100.0f, 1.0f, 60.0f);   // Scale to rectangular platform
    glutSolidCube(1.0f);             // Render a unit cube (scaled)
    glPopMatrix();

    // Draw the upper platform layer
    glPushMatrix();
    glColor3f(0.9f, 0.9f, 0.9f);     // Slightly lighter gray
    glTranslatef(0.0f, -1.0f, 0.0f); // Raise it above the base
    glScalef(80.0f, 1.0f, 50.0f);    // Slightly smaller than the base
    glutSolidCube(1.0f);
    glPopMatrix();

    // Draw black octagonal platform area
    glPushMatrix();
    glColor3f(0.0f, 0.0f, 0.0f);      // Black color
    glTranslatef(0.0f, -0.15f, 0.0f); // Raise slightly above upper layer
    glScalef(35.0f, 1.0f, 20.0f);     // Scaling factor

    // Define 8 vertices of a round-corner style octagon (XZ-plane, Y = 0)
    const float width = 1.0f;
    const float depth = 1.0f;
    const float cornerSize = 0.3f;

    GLfloat vertices[8][3] = {
        {width, 0.0f, depth - cornerSize},
        {width - cornerSize, 0.0f, depth},
        {-width + cornerSize, 0.0f, depth},
        {-width, 0.0f, depth - cornerSize},
        {-width, 0.0f, -depth + cornerSize},
        {-width + cornerSize, 0.0f, -depth},
        {width - cornerSize, 0.0f, -depth},
        {width, 0.0f, -depth + cornerSize}};

    glBegin(GL_POLYGON); // Draw filled octagon
    for (int i = 0; i < 8; ++i)
    {
        glVertex3fv(vertices[i]);
    }
    glEnd();
    glPopMatrix();

    // Draw inner green grassy field (inside the black octagon)
    glPushMatrix();
    glColor3f(0.2f, 0.7f, 0.3f);     // Green color for grass
    glTranslatef(0.0f, -0.1f, 0.0f); // Slightly above the black platform
    glScalef(30.0f, 1.0f, 16.0f);    // Slightly smaller scale

    glBegin(GL_POLYGON); // Draw filled green polygon with same vertices
    for (int i = 0; i < 8; ++i)
    {
        glVertex3fv(vertices[i]);
    }
    glEnd();
    glPopMatrix();

    // Draw Pokeball center decoration
    glPushMatrix();
    glRotatef(90.0f, 1.0f, 0.0f, 0.0f); // Rotate to lay flat on XZ-plane

    // Red upper half
    glColor3f(1.0f, 0.0f, 0.0f);
    gluPartialDisk(pObj, 0.0f, 10.0f, 52, 26, 0.0f, 180.0f);

    // White lower half
    glColor3f(1.0f, 1.0f, 1.0f);
    gluPartialDisk(pObj, 0.0f, 10.0f, 52, 26, 180.0f, 180.0f);

    // Black ring on top of red-white
    glColor3f(0.0f, 0.0f, 0.0f);
    glTranslatef(0.0f, 0.0f, -0.1f); // Small offset to avoid Z-fighting
    gluDisk(pObj, 2.0f, 3.0f, 52, 26);

    // White center button
    glColor3f(0.7f, 0.7f, 0.7f);
    glTranslatef(0.0f, 0.01f, 0.0f); // Slight upward offset
    gluDisk(pObj, 0.0f, 2.0f, 52, 26);

    // Outer black ring
    glColor3f(0.0f, 0.0f, 0.0f);
    glTranslatef(0.0f, 0.0f, 0.1f); // Move up again to layer properly
    gluDisk(pObj, 10.0f, 11.0f, 52, 26);

    glPopMatrix();

    gluDeleteQuadric(pObj); // Free memory used by quadric object
    glEnable(GL_CULL_FACE); // Re-enable back-face culling
}

