//------------------------------------------------Umbreon--------------------------------------

void Umbreon::toggleStanding()
{
    if (!isAnimating)
    { // Now refers to class member
        // Start animation
        isAnimating = true;
        isReturning = false;
        holdTimer = 0.0f;

        // Set target values for body animation
        targetBackBodyRotation = 32.4439f;
        targetTranslateX = -0.299103f;
        targetTranslateZ = 0.13775f;

        // Set target values for leg animation (standing position)
        targetLegTranslateX = -0.592798f;
    }
}

void Umbreon::updateAnimation()
{
    if (!isAnimating)
        return;

    // Arrays for current values, targets, and speeds
    float *currents[] = {&currentBackBodyRotation, &currentTranslateX, &currentTranslateZ, &currentLegTranslateX};
    float *targets[] = {&targetBackBodyRotation, &targetTranslateX, &targetTranslateZ, &targetLegTranslateX};
    float speeds[] = {rotationSpeed, translationSpeed, translationSpeed, translationSpeed};

    bool allComplete = true;
    for (int i = 0; i < 4; i++)
    {
        if (fabs(*currents[i] - *targets[i]) > speeds[i])
        {
            *currents[i] += (*currents[i] < *targets[i]) ? speeds[i] : -speeds[i];
            allComplete = false;
        }
        else
        {
            *currents[i] = *targets[i];
        }
    }

    if (!isReturning)
    {
        if (allComplete)
        {
            holdTimer += 1.0f;
            if (holdTimer >= holdDuration)
            {
                isReturning = true;
                for (int i = 0; i < 4; i++)
                    *targets[i] = 0.0f;
                holdTimer = 0.0f;
            }
        }
    }
    else if (allComplete)
    {
        isAnimating = isReturning = false;
        holdTimer = 0.0f;
    }
}

void Umbreon::updateFaintAnimation()
{
    if (!isFainted || faintAnimationComplete)
        return;

    faintAnimationTimer += 1.0f;      // Increment timer
    float animationDuration = 120.0f; // 2 seconds at 60fps

    if (faintAnimationTimer < animationDuration)
    {
        // Rotate from 0 to 90 degrees (laying down)
        float progress = faintAnimationTimer / animationDuration;
        faintRotation = progress * 75.0f;
    }
    else
    {
        faintRotation = 75.0f;
        faintAnimationComplete = true;
    }
}

void Umbreon::draw(const float vertices[][3], int numVertices,
                   const int faces[][3], int numFaces)
{
    glDisable(GL_CULL_FACE);

    for (int i = 0; i < numFaces; ++i)
    {
        glBegin(GL_TRIANGLES);
        for (int j = 0; j < 3; ++j)
        {
            int vIdx = faces[i][j];
            if (vIdx >= 0 && vIdx < numVertices)
            {
                glVertex3fv(vertices[vIdx]);
            }
        }
        glEnd();
    }

    glEnable(GL_CULL_FACE);
}

void Umbreon::drawmodel()
{

    glPushMatrix(); // Save current transformation

    // Rotate 90 degrees around X-axis
    glRotatef(-90.0f, 1.0f, 0.0f, 0.0f);
    // Apply faint rotation to entire Magneton group
    if (isFainted)
    {
        glRotatef(faintRotation, 1.0f, 0.0f, 0.0f);
    }

    glColor3f(0.0f, 0.0f, 0.0f); // Set color to black

    // Apply animation transformations to back body parts
    glPushMatrix();

    // Apply translation FIRST (this will be applied LAST)
glTranslatef(currentTranslateX, 0.0f, currentTranslateZ);
// Apply rotation SECOND (this will be applied FIRST)
glRotatef(currentBackBodyRotation, 0.0f, 1.0f, 0.0f);

    draw(vertices_Back_Body, numVertices_Back_Body, faces_Back_Body, numFaces_Back_Body);
    draw(vertices_Front_Body, numVertices_Front_Body, faces_Front_Body, numFaces_Front_Body);
    draw(vertices_Tail_Btm, numVertices_Tail_Btm, faces_Tail_Btm, numFaces_Tail_Btm);
    draw(vertices_Tail_Top, numVertices_Tail_Top, faces_Tail_Top, numFaces_Tail_Top);
    glColor3f(1.0f, 1.0f, 0.0f);
    draw(vertices_Tail_Mid, numVertices_Tail_Mid, faces_Tail_Mid, numFaces_Tail_Mid);
    draw(vertices_Right_Back_Tattoo, numVertices_Right_Back_Tattoo, faces_Right_Back_Tattoo, numFaces_Right_Back_Tattoo);
    draw(vertices_Left_Back_Tattoo, numVertices_Left_Back_Tattoo, faces_Left_Back_Tattoo, numFaces_Left_Back_Tattoo);
    glPopMatrix();

    // Rest of your model parts (these don't animate)
    glColor3f(0.0f, 0.0f, 0.0f);
    draw(vertices_Head, numVertices_Head, faces_Head, numFaces_Head);
    draw(vertices_Left_Btm_Ear, numVertices_Left_Btm_Ear, faces_Left_Btm_Ear, numFaces_Left_Btm_Ear);
    draw(vertices_Left_Mid_Eye, numVertices_Left_Mid_Eye, faces_Left_Mid_Eye, numFaces_Left_Mid_Eye);
    draw(vertices_Left_Top_Ear, numVertices_Left_Top_Ear, faces_Left_Top_Ear, numFaces_Left_Top_Ear);
    draw(vertices_Mouth, numVertices_Mouth, faces_Mouth, numFaces_Mouth);
    draw(vertices_Neck, numVertices_Neck, faces_Neck, numFaces_Neck);
    draw(vertices_Right_Btm_Ear, numVertices_Right_Btm_Ear, faces_Right_Btm_Ear, numFaces_Right_Btm_Ear);
    draw(vertices_Right_Mid_Eye, numVertices_Right_Mid_Eye, faces_Right_Mid_Eye, numFaces_Right_Mid_Eye);
    draw(vertices_Right_Top_Ear, numVertices_Right_Top_Ear, faces_Right_Top_Ear, numFaces_Right_Top_Ear);
    draw(vertices_Left_Leg, numVertices_Left_Leg, faces_Left_Leg, numFaces_Left_Leg);
    draw(vertices_Right_Leg, numVertices_Right_Leg, faces_Right_Leg, numFaces_Right_Leg);
    draw(vertices_Left_Foot, numVertices_Left_Foot, faces_Left_Foot, numFaces_Left_Foot);
    draw(vertices_Right_Foot, numVertices_Right_Foot, faces_Right_Foot, numFaces_Right_Foot);

    // Draw back legs only when currentLegTranslateX is near 0 (sitting position)
    if (fabs(currentLegTranslateX) < 0.1f)
    { // Reduced threshold for faster switching
        draw(vertices_Right_Back_Leg, numVertices_Right_Back_Leg, faces_Right_Back_Leg, numFaces_Right_Back_Leg);
        draw(vertices_Left_Back_Leg, numVertices_Left_Back_Leg, faces_Left_Back_Leg, numFaces_Left_Back_Leg);
    }
    else
    {
        // Animated legs - use currentLegTranslateX for smooth transition
        glPushMatrix();
        glTranslatef(currentLegTranslateX, 0, 0);
        draw(vertices_Left_Leg, numVertices_Left_Leg, faces_Left_Leg, numFaces_Left_Leg);
        draw(vertices_Right_Leg, numVertices_Right_Leg, faces_Right_Leg, numFaces_Right_Leg);
        draw(vertices_Left_Foot, numVertices_Left_Foot, faces_Left_Foot, numFaces_Left_Foot);
        draw(vertices_Right_Foot, numVertices_Right_Foot, faces_Right_Foot, numFaces_Right_Foot);
        glPopMatrix();
    }

    // Draw in red
    glColor3f(1.0f, 0.0f, 0.0f);
    draw(vertices_Right_Btm_Eye, numVertices_Right_Btm_Eye, faces_Right_Btm_Eye, numFaces_Right_Btm_Eye);
    draw(vertices_Left_Btm_Eye, numVertices_Left_Btm_Eye, faces_Left_Btm_Eye, numFaces_Left_Btm_Eye);

    // Draw in white
    glColor3f(1.0f, 1.0f, 1.0f);
    draw(vertices_Right_Top_Eye, numVertices_Right_Top_Eye, faces_Right_Top_Eye, numFaces_Right_Top_Eye);
    draw(vertices_Left_Top_Eye, numVertices_Left_Top_Eye, faces_Left_Top_Eye, numFaces_Left_Top_Eye);
    draw(vertices_Mouth_Line, numVertices_Mouth_Line, faces_Mouth_Line, numFaces_Mouth_Line);

    // Draw in yellow
    glColor3f(1.0f, 1.0f, 0.0f);
    draw(vertices_Right_Mid_Ear, numVertices_Right_Mid_Ear, faces_Right_Mid_Ear, numFaces_Right_Mid_Ear);
    draw(vertices_Left_Mid_Ear, numVertices_Left_Mid_Ear, faces_Left_Mid_Ear, numFaces_Left_Mid_Ear);
    draw(vertices_Head_Tattoo, numVertices_Head_Tattoo, faces_Head_Tattoo, numFaces_Head_Tattoo);
    draw(vertices_Left_Front_Tattoo, numVertices_Left_Front_Tattoo, faces_Left_Front_Tattoo, numFaces_Left_Front_Tattoo);
    draw(vertices_Right_Front_Tattoo, numVertices_Right_Front_Tattoo, faces_Right_Front_Tattoo, numFaces_Right_Front_Tattoo);

    glPopMatrix(); // Restore transformation
}

