//----------------------------------MyVirtualWorld draw-------------------------------------

void MyVirtualWorld::draw()
{

    // ####battle platform
    pokemon_1.drawPokemon(magnemite);
    pokemon_2.drawPokemon(umbreon);
    if (skill_1.shouldDraw())
    {
        skill_1.drawThunderShock();
    }

    if (skill_2.shouldDraw())
    {
        skill_2.drawFeintAttack();
    }

    if (skill_3.shouldDraw())
    {
        skill_3.drawThunderbolt();
    }

    if (skill_4.shouldDraw())
    {
        skill_4.drawAssurance();
    }
    // Draw 3D battlefield
    battle_plat.drawPlat();

    // Get window dimensions
    int winWidth = glutGet(GLUT_WINDOW_WIDTH);
    int winHeight = glutGet(GLUT_WINDOW_HEIGHT);

    // Save current OpenGL state
    glPushAttrib(GL_ENABLE_BIT | GL_TRANSFORM_BIT);

    // Switch to 2D orthographic projection
    glMatrixMode(GL_PROJECTION);
    glPushMatrix();
    glLoadIdentity();
    gluOrtho2D(0, winWidth, 0, winHeight);
    glMatrixMode(GL_MODELVIEW);
    glPushMatrix();
    glLoadIdentity();

    // Disable 3D rendering states for clean 2D rendering
    glDisable(GL_DEPTH_TEST);
    glDisable(GL_LIGHTING);
    glDisable(GL_COLOR_MATERIAL);
    glDisable(GL_CULL_FACE);

    // Draw Pokemon UI
    drawPokemonUI(20, winHeight - 20, "Magnemite(Magneton)", 100, playerHP, 100, true, ' ');
    drawPokemonUI(winWidth - 270, winHeight - 20, "Umbreon", 100, enemyHP, 100, false, 'F');

    // Draw menu based on whose turn it is
    if (currentTurnState == PLAYER1_SELECTING)
    {
        drawSkillMenu(100.0f, 200.0f, player1Skills, "Magnemite(Magneton) 's Turn", selectedSkillP1, "Electric");
    }
    else if (currentTurnState == PLAYER2_SELECTING)
    {
        drawSkillMenu(100.0f, 200.0f, player2Skills, "Umbreon's Turn", selectedSkillP2, "Dark");
    }

    // Show status message
    drawStatusMessage(statusMessage);

    // Restore 3D projection matrices
    glPopMatrix();
    glMatrixMode(GL_PROJECTION);
    glPopMatrix();
    glMatrixMode(GL_MODELVIEW);

    // Restore previous OpenGL state (including lighting, depth test, etc.)
    glPopAttrib();
}

